import java.util.concurrent.CountDownLatch;
import java.util.concurrent.ExecutionException;
import java.util.concurrent.ExecutorService;
import java.util.concurrent.Executors;
import java.util.concurrent.Future;
import java.util.concurrent.ThreadFactory;
import java.util.concurrent.TimeUnit;
import java.util.concurrent.atomic.AtomicInteger;

public final class TextDaemon implements AutoCloseable {
    private final ExecutorService workers;
    private final ExecutorService reloadExecutor;
    private final TimelineLedger revisions;
    private final int workerCount;

    public TextDaemon(Path pluginJar, int workerCount) {
        this.revisions = new TimelineLedger(pluginJar);
        this.workers = Executors.newFixedThreadPool(workerCount, new WorkerThreadFactory());
        this.reloadExecutor = Executors.newSingleThreadExecutor(r -> {
            Thread t = new Thread(r, "textd-reload");
            t.setDaemon(true);
            return t;
        });
        this.workerCount = workerCount;
    }

    public void reload(long generation) throws Exception {
        revisions.install(generation);
        reloadExecutor.submit(this::primeWorkerBindings).get();
    }

    public ProcessingResult process(String record) throws Exception {
        return processBatch(List.of(record)).get(0);
    }

    public boolean isBalanced() {
        return revisions.isBalanced();
    }

    public List<ProcessingResult> processBatch(List<String> records) throws Exception {
        CountDownLatch ready = new CountDownLatch(records.size());
        CountDownLatch release = new CountDownLatch(1);
        List<Future<ProcessingResult>> futures = new ArrayList<>();
        for (String record : records) {
            futures.add(workers.submit(() -> processRecord(record, ready, release)));
        }

        if (!ready.await(5, TimeUnit.SECONDS)) {
            throw new IllegalStateException("Workers did not become ready");
        }
        release.countDown();

        List<ProcessingResult> results = new ArrayList<>(records.size());
        for (Future<ProcessingResult> future : futures) {
            results.add(await(future));
        }
        return results;
    }

    private ProcessingResult processRecord(
        String record,
        CountDownLatch ready,
        CountDownLatch release
    ) throws Exception {
        ready.countDown();
        if (!release.await(5, TimeUnit.SECONDS)) {
            throw new IllegalStateException("Request release timed out");
        }

        WorkerHandle binding = ThreadBridge.current(revisions);
        return binding.process(record);
    }

    private void primeWorkerBindings() throws Exception {
        runOnWorkers(() -> ThreadBridge.current(revisions));
    }

    @Override
    public void close() throws Exception {
        Throwable failure = null;
        try {
            clearWorkerBindings();
        } catch (Throwable throwable) {
            failure = throwable;
        }
        try {
            await(reloadExecutor.submit(() -> {
                ThreadBridge.clear();
                return null;
            }));
        } catch (Throwable throwable) {
            failure = append(failure, throwable);
        }
        try {
            revisions.close();
        } catch (Throwable throwable) {
            failure = append(failure, throwable);
        } finally {
            reloadExecutor.shutdownNow();
            workers.shutdownNow();
            try {
                reloadExecutor.awaitTermination(5, TimeUnit.SECONDS);
            } catch (InterruptedException interrupted) {
                Thread.currentThread().interrupt();
                failure = append(failure, interrupted);
            }
            try {
                workers.awaitTermination(5, TimeUnit.SECONDS);
            } catch (InterruptedException interrupted) {
                Thread.currentThread().interrupt();
                failure = append(failure, interrupted);
            }
        }

        rethrow(failure);
    }

    private void clearWorkerBindings() throws Exception {
        runOnWorkers(ThreadBridge::clear);
    }

    private void runOnWorkers(WorkerAction action) throws Exception {
        CountDownLatch ready = new CountDownLatch(workerCount);
        CountDownLatch release = new CountDownLatch(1);
        List<Future<Void>> futures = new ArrayList<>(workerCount);
        for (int index = 0; index < workerCount; index++) {
            futures.add(workers.submit(() -> {
                ready.countDown();
                if (!release.await(5, TimeUnit.SECONDS)) {
                    throw new IllegalStateException("Worker synchronization timed out");
                }
                action.run();
                return null;
            }));
        }

        if (!ready.await(5, TimeUnit.SECONDS)) {
            throw new IllegalStateException("Workers did not become ready");
        }
        release.countDown();

        for (Future<Void> future : futures) {
            await(future);
        }
    }

    private static <T> T await(Future<T> future) throws Exception {
        try {
            return future.get();
        } catch (ExecutionException exception) {
            Throwable cause = exception.getCause();
            if (cause instanceof Exception checked) {
                throw checked;
            }
            if (cause instanceof Error error) {
                throw error;
            }
            throw new RuntimeException(cause);
        }
    }

    private static Throwable append(Throwable failure, Throwable throwable) {
        if (failure == null) {
            return throwable;
        }
        failure.addSuppressed(throwable);
        return failure;
    }

    private static void rethrow(Throwable throwable) throws Exception {
        if (throwable == null) {
            return;
        }
        if (throwable instanceof Exception checked) {
            throw checked;
        }
        if (throwable instanceof Error error) {
            throw error;
        }
        throw new RuntimeException(throwable);
    }

    private static final class WorkerThreadFactory implements ThreadFactory {
        private final AtomicInteger sequence = new AtomicInteger(1);

        @Override
        public Thread newThread(Runnable runnable) {
            Thread thread = new Thread(runnable);
            thread.setName("textd-worker-" + sequence.getAndIncrement());
            thread.setDaemon(true);
            return thread;
        }
    }

    @FunctionalInterface
    private interface WorkerAction {
        void run() throws Exception;
    }
